import { useCallback, useEffect, useState } from "react";

import { useLocation, useNavigate } from "react-router-dom";
import { useUser } from "@/hooks/useUser";
import { usePost } from "@/hooks/usePost";
import { getAvatarUrl, getUserTags } from "@/utils/userUtil";
import { getUserCallOrderRank } from "@/http/api";
import { openEmailClient } from "@/utils/bridge";
import { toast } from "@/utils/toast";
import PostList from "./PostList";
import EmptyView from "@/components/EmptyView";
import { bpTrack } from "@/tracking";
import { EventName } from "@/tracking/events";

// 图标资源
import icHelper from "@/assets/images/profile/helper.webp";
import icSetting from "@/assets/images/profile/setting.webp";
import icStar from "@/assets/images/profile/star.webp";
import icEdit from "@/assets/images/profile/edit.webp";
import icUpload from "@/assets/images/ic_upload.webp";
import DetailItems from "@/components/DetailItems";

/** Help & Feedback 邮箱地址 */
const HELP_EMAIL = "contact@gracechat.com";

export default function Me() {
  const { pathname } = useLocation();
  const navigate = useNavigate();
  const { userInfo, paypalAccount, fetchPaypalAccount } = useUser();
  const { myPosts, isLoading, hasMore, fetchMyPosts } = usePost();
  const [callOrderRank, setCallOrderRank] = useState(0);

  useEffect(() => {
    if (!userInfo?.userId) return;
    getUserCallOrderRank(userInfo.userId).then((res) => {
      setCallOrderRank(res.callOrderRank || 0);
    });
  }, [userInfo?.userId]);

  // 获取 PayPal 账号绑定状态
  useEffect(() => {
    fetchPaypalAccount();
  }, [fetchPaypalAccount]);

  useEffect(() => {
    if (pathname !== "/me") return;
    bpTrack(EventName.pwa_profile_page_show);
    fetchMyPosts(true);
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [pathname]);

  // 用户信息字段
  const username = userInfo?.username || "N/A";
  const age = userInfo?.age || "N/A";
  const tags = getUserTags(userInfo, 5);
  const userId = userInfo?.userId;

  // 头像 URL
  const avatarUrl = getAvatarUrl(userInfo);

  // rerender-use-callback: 使用 useCallback 稳定回调引用
  const handleSettingsClick = useCallback(() => {
    navigate("/settings");
  }, [navigate]);

  const handleHelpClick = useCallback(() => {
    openEmailClient(HELP_EMAIL, "Help & Feedback");
  }, []);

  const handleEditProfileClick = useCallback(() => {
    bpTrack(EventName.pwa_mepage_change_avatar_click);
    bpTrack(EventName.pwa_profile_edit_click);
    navigate("/avatar");
  }, [navigate]);

  const handleAddTagsClick = useCallback(() => {
    navigate("/tags");
  }, [navigate]);

  const handleCreatePostClick = useCallback(() => {
    bpTrack(EventName.pwa_profile_create_post_click);
    navigate("/createPost");
  }, [navigate]);

  /** 一键复制 UserID，复制成功后 toast 提示 */
  const handleCopyUserId = useCallback(() => {
    if (!userId) return;
    navigator.clipboard.writeText(String(userId)).then(() => {
      toast.success("Copied!");
    });
  }, [userId]);

  if (!userInfo) {
    return <EmptyView className="h-full" />;
  }

  return (
    <div className="flex flex-col w-full h-full bg-surface overflow-y-auto">
      {/* 头部背景区域 */}
      <div
        className="relative flex flex-col w-full min-h-[320px] bg-cover bg-center"
        style={{
          backgroundImage: `linear-gradient(rgba(0,0,0,0.2), rgba(0,0,0,0.5)), url('${avatarUrl}')`,
        }}
      >
        {/* 顶部导航栏：Profile 标题 + 帮助 + 设置 */}
        <div className="flex items-center justify-between w-full px-4 pt-[calc(var(--sat,0px)+12px)]">
          <span className="text-white text-2xl font-bold drop-shadow-md">Profile</span>
          <div className="flex items-center gap-1">
            <button
              onClick={handleHelpClick}
              className="p-3 bg-transparent border-none cursor-pointer"
              aria-label="Help & Feedback"
            >
              <img src={icHelper} alt="Help" className="w-6 h-6 drop-shadow-md" />
            </button>
            <button
              onClick={handleSettingsClick}
              className="p-3 bg-transparent border-none cursor-pointer"
              aria-label="Settings"
            >
              <img src={icSetting} alt="Settings" className="w-6 h-6 drop-shadow-md" />
            </button>
          </div>
        </div>

        {/* 头部内容 */}
        <div className="flex flex-col items-center justify-end w-full px-3 pt-4 pb-5">
          <div className="w-full px-1">
            {/* 头像和基本信息 */}
            <div className="flex items-center w-full mt-3 mb-4">
              {/* 头像（带编辑按钮） */}
              <div className="relative mr-4 shrink-0">
                <img
                  src={avatarUrl}
                  alt="Profile"
                  className="w-[83px] h-[83px] rounded-full border-2 border-white object-cover shadow-lg"
                />
                <button
                  onClick={handleEditProfileClick}
                  className="absolute bottom-0 right-0 w-6 h-6 flex items-center justify-center rounded-full bg-white shadow-md border-none cursor-pointer p-0"
                  aria-label="Edit profile"
                >
                  <img src={icEdit} alt="Edit" className="w-5 h-5" />
                </button>
              </div>

              {/* 姓名 • 年龄 + 等级徽章同行 */}
              <div className="flex flex-col flex-1 min-w-0">
                <div className="flex items-center gap-2 min-w-0">
                  <h1 className="m-0 text-white text-2xl font-bold leading-tight drop-shadow-lg flex items-baseline min-w-0 overflow-hidden">
                    <span className="truncate">{username}</span>
                    <span className="mx-1 font-normal shrink-0">•</span>
                    <span className="shrink-0">{age}</span>
                  </h1>
                  <div className="flex items-center gap-1 px-2.5 py-1 bg-white/20 backdrop-blur-sm rounded-full shrink-0">
                    <img src={icStar} alt="Star" className="w-4 h-4" />
                    <span className="text-white text-sm font-medium">Lv.{callOrderRank}</span>
                  </div>
                </div>

                {/* UserID（Lv 下方，点击复制） */}
                {userId && (
                  <button
                    onClick={handleCopyUserId}
                    className="mt-1.5 bg-transparent border-none cursor-pointer p-0 self-start"
                    aria-label="Copy user ID"
                  >
                    <span className="text-white/90 text-sm drop-shadow">ID: {userId}</span>
                  </button>
                )}
              </div>
            </div>

            {/* 详情信息 */}
            <DetailItems
              paypalAccount={paypalAccount}
              hometown={userInfo?.geoLocation?.city}
              profession={userInfo?.profession}
              bio={userInfo?.bio}
              tags={tags}
              onAddTags={handleAddTagsClick}
            />
          </div>
        </div>
      </div>

      {/* 帖子列表 */}
      <div className="flex-1 w-full">
        <PostList posts={myPosts} isLoading={isLoading} hasMore={hasMore} onLoadMore={fetchMyPosts} />
      </div>

      {/* 发帖按钮 */}
      <button
        onClick={handleCreatePostClick}
        className="fixed right-4 bottom-24 w-14 h-14 p-0 border-none bg-transparent cursor-pointer z-10"
      >
        <img src={icUpload} alt="Create Post" className="w-14 h-14" />
      </button>
    </div>
  );
}
